def detect_flakiness(func, n_runs=10):
    def safe_runner(f):
        try:
            return f()
        except Exception:
            return None

    results = set()

    for _ in range(n_runs):
        result = safe_runner(func)
        if result is not None:
            results.add(result)

    return len(results) > 1

